const b = $json.body || {};

// 1) Identify ALL selected sectors (checkboxes like sectors[0], sectors[1], etc.)
const selectedSectors = Object.keys(b)
  .filter(k => k.startsWith("sectors["))
  .map(k => b[k])
  .filter(Boolean);

// 2) Date formatting (DD/MM/YYYY -> YYYY-MM-DD)
let formattedDate = "";
if (b.date && b.date.includes("/")) {
  const [d, m, y] = b.date.split("/");
  formattedDate = `${y}-${m}-${d}`;
}

return [{
  json: {
    user: {
      name: b.name,
      email: b.email_address,
      company: b.company_name
    },
    research: {
      topic: b.what_would_you_like_us_to_research,
      published_after: formattedDate
    },
    selected_sectors: selectedSectors
  }
}];

