// This expects Suggest URLs returned JSON only
const raw = items[0].json.output?.[0]?.content?.[0]?.text
  || items[0].json.output?.[0]?.content
  || items[0].json.text
  || items[0].json;

let parsed;
try {
  parsed = typeof raw === "string" ? JSON.parse(raw) : raw;
} catch (e) {
  // fallback: keep raw for debugging
  return [{ json: { urls_raw: raw, parse_error: e.message } }];
}

const selected = parsed.selected || [];

const urlsBullets = selected
  .map((x, idx) => `${idx + 1}. ${x.name} — ${x.url}\n   ${x.reason}`)
  .join("\n\n");

return [{
  json: {
    selected,
    urls_bullets: urlsBullets
  }
}];
